template <typename T>
class Node {
public:
    T value;
    Node<T>* next;

    Node(T val) {
        value = val;
        next = nullptr;
    }
};

template <typename T>
class LinkedList {
private:
    Node<T>* head;
    int count;

public:
    LinkedList() {
        head = nullptr;
        count = 0;
    }

    void insertAt(int pos, T val) {
        if (pos < 0 || pos > count) {
            return;
        }

        Node<T>* newNode = new Node<T>(val);

        if (pos == 0) {
            newNode->next = head;
            head = newNode;
            count++;
            return;
        }

        Node<T>* current = head;
        for (int i = 0; i < pos - 1; i++) {
            current = current->next;
        }

        newNode->next = current->next;
        current->next = newNode;
        count++;
    }
};

