double average(std::queue<int> q) {
    if (q.empty()) {
        return 0;
    }

    int sum = 0;
    int n = q.size();

    for (int i = 0; i < n; i++) {
        int x = q.front();
        q.pop();
        sum += x;
        q.push(x);
    }

    return (double)sum / n;
}
